const item = $input.first();
const body = item.json || {};
const binary = item.binary || {};

const batchId = (body.batchId || '').toString().trim();
const jobTitle = (body.jobTitle || '').toString().trim();
const jobDescription = (body.jobDescription || '').toString().trim();
const mustHaveSkills = (body.mustHaveSkills || '').toString().trim();
const niceToHaveSkills = (body.niceToHaveSkills || '').toString().trim();

const fileKeys = Object.keys(binary).filter((k) => k.toLowerCase().startsWith('files'));
const totalFiles = fileKeys.length;

const errors = [];
if (!batchId) errors.push('Missing batchId');
if (!jobDescription) errors.push('Missing jobDescription');
if (totalFiles === 0) errors.push('No resume files uploaded');

const nonPdf = fileKeys.filter((k) => {
  const mime = (binary[k].mimeType || '').toLowerCase();
  return mime !== 'application/pdf';
});
if (nonPdf.length > 0) errors.push('Only PDF resumes are supported (' + nonPdf.length + ' non-PDF file(s) rejected)');

return [{
  json: {
    isValid: errors.length === 0,
    validationError: errors.join('; '),
    batchId,
    jobTitle,
    jobDescription,
    mustHaveSkills,
    niceToHaveSkills,
    totalFiles
  },
  binary
}];

const items = $input.all();
const results = [];

for (const item of items) {
  const binary = item.binary || {};
  const fileKeys = Object.keys(binary).filter((k) => k.toLowerCase().startsWith('files'));

  for (const key of fileKeys) {
    const bin = binary[key];
    results.push({
      json: {
        batchId: item.json.batchId,
        jobTitle: item.json.jobTitle,
        jobDescription: item.json.jobDescription,
        mustHaveSkills: item.json.mustHaveSkills,
        niceToHaveSkills: item.json.niceToHaveSkills,
        totalFiles: item.json.totalFiles,
        fileName: bin.fileName || key
      },
      binary: { data: bin }
    });
  }
}

return results;

// n8n's continueErrorOutput items don't reliably carry a `text` field, so its
// absence (vs. present-but-short) is how we tell "extraction failed" apart from
// "extracted fine but the PDF had no real text (e.g. a scanned image)".
