let errorMessage;
if (!hasTextField) {
  errorMessage = 'PDF extraction failed' + ($json.error && $json.error.message ? ': ' + $json.error.message : '');
} else {
  errorMessage = 'No extractable text found (resume may be a scanned image PDF)';
}

return {
  json: {
    batchId: source.batchId,
    fileName: source.fileName,
    errorMessage,
    occurredAt: new Date().toISOString()
  }
};

