const meta = $('Split Resume Files').item.json;
const profile = $json.output || $json;

const rubric = `Score this candidate for the role below using this weighted rubric (integers, must sum to the max for each category):
- Skills Match (0-30): overlap between candidate skills and must-have/nice-to-have skills
- Experience Relevance (0-25): relevance and seniority of past roles vs this job
- Achievements & Impact (0-20): concrete, measurable accomplishments
- Education & Certifications (0-10): relevance of degrees/certifications
- Resume Clarity (0-15): how clearly the resume communicates the above

Overall score = sum of the five category scores (0-100).`;

const scoringText = `JOB TITLE: ${meta.jobTitle || 'Not specified'}
JOB DESCRIPTION:
${meta.jobDescription}

MUST-HAVE SKILLS: ${meta.mustHaveSkills || 'Not specified'}
NICE-TO-HAVE SKILLS: ${meta.niceToHaveSkills || 'Not specified'}

${rubric}

CANDIDATE PROFILE (already extracted from resume):
${JSON.stringify(profile)}`;

return {
  json: {
    ...meta,
    profile,
    scoringText
  }
};

